  <div class="col-12"><label class="form-label" for="descripcionCorta">Descripción corta *</label><input class="form-control" id="descripcionCorta" name="descripcion_corta" maxlength="500" value="<?=atenea_e((string)$producto['descripcion_corta'])?>" required></div><div class="col-12"><label class="form-label" for="descripcionProducto">Descripción completa *</label><textarea class="form-control" id="descripcionProducto" rows="5" name="descripcion" maxlength="10000" required><?=atenea_e((string)$producto['descripcion'])?></textarea></div>
  <div class="col-md-4"><label class="form-label" for="stockProducto">Stock</label><input class="form-control" id="stockProducto" type="number" min="<?=(int)$producto['stock_reservado']?>" name="stock" value="<?=atenea_e((string)$producto['stock'])?>"></div><div class="col-md-4"><label class="form-label" for="stockMinimo">Stock mínimo</label><input class="form-control" id="stockMinimo" type="number" min="0" name="stock_minimo" value="<?=atenea_e((string)$producto['stock_minimo'])?>"></div><div class="col-md-4 d-flex align-items-end gap-3"><div class="form-check form-switch mb-2"><input class="form-check-input" id="productoDisponible" type="checkbox" name="disponible" <?=$producto['disponible']?'checked':''?>><label class="form-check-label" for="productoDisponible">Disponible</label></div><div class="form-check form-switch mb-2"><input class="form-check-input" id="productoActivo" type="checkbox" name="activo" <?=$producto['activo']?'checked':''?>><label class="form-check-label" for="productoActivo">Activo</label></div></div>
  <div class="col-md-6"><label class="form-label" for="imagenPrincipal">Imagen principal</label><input class="form-control" id="imagenPrincipal" type="file" name="imagen_principal" accept=".jpg,.jpeg,.png,.webp,image/jpeg,image/png,image/webp"></div><div class="col-md-6"><label class="form-label" for="galeriaProducto">Galería</label><input class="form-control" id="galeriaProducto" type="file" name="galeria[]" multiple accept=".jpg,.jpeg,.png,.webp,image/jpeg,image/png,image/webp"></div>
  <div class="col-12"><hr><h2 class="h5">Promoción</h2></div><div class="col-md-2"><div class="form-check form-switch"><input class="form-check-input" id="promocionActiva" type="checkbox" name="promo_activa" <?=$promocion&&$promocion['activa']?'checked':''?>><label class="form-check-label" for="promocionActiva">Activa</label></div></div><div class="col-md-3"><label class="visually-hidden" for="etiquetaPromocion">Etiqueta</label><input class="form-control" id="etiquetaPromocion" name="promo_etiqueta" maxlength="100" placeholder="Etiqueta" value="<?=atenea_e((string)($promocion['etiqueta']??''))?>"></div><div class="col-md-2"><label class="visually-hidden" for="precioOferta">Precio de oferta</label><input class="form-control" id="precioOferta" type="number" min="0" step="0.01" name="precio_promocional" placeholder="Precio oferta" value="<?=atenea_e((string)($promocion['precio_promocional']??''))?>"></div><div class="col-md-2"><label class="visually-hidden" for="inicioPromocion">Inicio</label><input class="form-control" id="inicioPromocion" type="datetime-local" name="promo_inicio" value="<?=$promocion?date('Y-m-d\TH:i',strtotime((string)$promocion['fecha_inicio'])):''?>"></div><div class="col-md-3"><label class="visually-hidden" for="finPromocion">Fin</label><input class="form-control" id="finPromocion" type="datetime-local" name="promo_fin" value="<?=$promocion?date('Y-m-d\TH:i',strtotime((string)$promocion['fecha_fin'])):''?>"></div>
